function containsPattern(arr, m, k) {
    const n = arr.length;
    if (m * k > n) return false;

    for (let i = 0; i + m * k <= n; i++) {
        let patternFound = true;
        for (let j = 0; j < m; j++) {
            for (let l = 1; l < k; l++) {
